class AuthenticationService(AuthenticationServiceServicer):
    def __init__(self):
        self.users = {
            'admin': self._hash_password('admin123'),
            'user1': self._hash_password('password1'),
            'testuser': self._hash_password('test123')
        }
        self.secret_key = os.environ.get('JWT_SECRET_KEY', secrets.token_hex(32))
        self.token_expiry = 3600  # 1 hour
    
    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()
    
    def _generate_token(self, username: str) -> str:
        payload = {
            'username': username,
            'exp': datetime.utcnow() + timedelta(seconds=self.token_expiry),
            'iat': datetime.utcnow()
        }
        return jwt.encode(payload, self.secret_key, algorithm='HS256')
    
    def _validate_token(self, token: str) -> Optional[str]:
        try:
            payload = jwt.decode(token, self.secret_key, algorithms=['HS256'])
            return payload.get('username')
        except jwt.ExpiredSignatureError:
            return None
        except jwt.InvalidTokenError:
            return None
    
    def Login(self, request, context):
        username = request.username
        password = request.password
        
        if username in self.users and self.users[username] == self._hash_password(password):
            token = self._generate_token(username)
            return LoginResponse(success=True, token=token, message='Login successful')
        else:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details('Invalid credentials')
            return LoginResponse(success=False, token='', message='Invalid username or password')
    
    def ValidateToken(self, request, context):
        username = self._validate_token(request.token)
        if username:
            return ValidateTokenResponse(valid=True, username=username)
        else:
            return ValidateTokenResponse(valid=False, username='')

class DataRetrievalService(DataRetrievalServiceServicer):
    def __init__(self, auth_service: AuthenticationService):
        self.auth_service = auth_service
        self.data_store = {
            'data1': {'name': 'User Profile', 'value': '{"age": 30, "city": "NYC"}'},
            'data2': {'name': 'Settings', 'value': '{"theme": "dark", "lang": "en"}'},
            'data3': {'name': 'Preferences', 'value': '{"notifications": true}'},
        }
        self.lock = threading.Lock()
    
    def _authenticate_request(self, token: str, context) -> Optional[str]:
        username = self.auth_service._validate_token(token)
        if not username:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details('Invalid or expired token')
            return None
        return username
    
    def GetData(self, request, context):
        username = self._authenticate_request(request.token, context)
        if not username:
            return DataResponse(success=False, data='', message='Authentication failed')
        
        with self.lock:
            if request.data_id in self.data_store:
                data = self.data_store[request.data_id]
                return DataResponse(success=True, data=data['value'], message='Data retrieved successfully')
            else:
                context.set_code(grpc.StatusCode.NOT_FOUND)
                return DataResponse(success=False, data='', message='Data not found')
    
    def ListData(self, request, context):
        username = self._authenticate_request(request.token, context)
        if not username:
            return ListDataResponse(success=False, items=[], message='Authentication failed')
        
        with self.lock:
            items = []
            for data_id, data in list(self.data_store.items())[:request.limit]:
                items.append(DataItem(id=data_id, name=data['name'], value=data['value']))
            return ListDataResponse(success=True, items=items, message='Data listed successfully')

# TLS Certificate Generation Helper
def generate_self_signed_cert():
    from cryptography import x509
    from cryptography.x509.oid import NameOID
    from cryptography.hazmat.primitives import hashes
    from cryptography.hazmat.primitives.asymmetric import rsa
    from cryptography.hazmat.primitives import serialization
    
    key = rsa.generate_private_key(public_exponent=65537, key_size=2048)
    
    subject = issuer = x509.Name([
        x509.NameAttribute(NameOID.COUNTRY_NAME, u"US"),
        x509.NameAttribute(NameOID.STATE_OR_PROVINCE_NAME, u"State"),
        x509.NameAttribute(NameOID.LOCALITY_NAME, u"City"),
        x509.NameAttribute(NameOID.ORGANIZATION_NAME, u"Organization"),
        x509.NameAttribute(NameOID.COMMON_NAME, u"localhost"),
    ])
    
    cert = x509.CertificateBuilder().subject_name(
        subject
    ).issuer_name(
        issuer
    ).public_key(
        key.public_key()
    ).serial_number(
        x509.random_serial_number()
    ).not_valid_before(
        datetime.utcnow()
    ).not_valid_after(
        datetime.utcnow() + timedelta(days=365)
    ).add_extension(
        x509.SubjectAlternativeName([x509.DNSName(u"localhost")]),
        critical=False,
    ).sign(key, hashes.SHA256())
    
    cert_pem = cert.public_bytes(serialization.Encoding.PEM)
    key_pem = key.private_bytes(
        encoding=serialization.Encoding.PEM,
        format=serialization.PrivateFormat.TraditionalOpenSSL,
        encryption_algorithm=serialization.NoEncryption()
    )
    
    return cert_pem, key_pem

